 import { Injectable, signal, computed, inject, effect } from '@angular/core';
 import { ToastService } from './toast.service';
 import { supabase } from '../supabase';

export type UserRole = 'ADMIN' | 'COLLABORATOR' | null;

export interface AdminCompany {
  name: string;
  piva: string;
  address: string;
  phone: string;
  cellphone: string;
  whatsapp: string;
  email: string;
  pec: string;
  sdi: string;
  licenseNumber: string;
  logo?: string;
}

export interface ClientEntity {
  id: string;
  name: string;
  piva: string;
  address: string;
  phone: string;
  cellphone?: string;
  whatsapp?: string;
  email: string;
  licenseNumber: string;
  suspended: boolean; // Service suspension for non-payment
  logo?: string;
}

export interface SystemUser {
  id: string;
  name: string;
  email: string;
  role: UserRole;
  department?: string;
  active: boolean;
  avatar: string;
  clientId?: string; // Link to the specific Company/Client
  username?: string;
  password?: string;
}

export interface User {
  id: string;
  name: string;
  role: UserRole;
  avatar: string;
  department?: string;
  clientId?: string;
}

export interface MenuItem {
  id: string;
  label: string;
  icon: string;
  category: 'dashboard' | 'operations' | 'history' | 'monitoring' | 'config' | 'communication' | 'production' | 'documentation';
  adminOnly?: boolean;
  operatorOnly?: boolean;
}

export interface Message {
  id: string;
  senderId: string;
  senderName: string;
  recipientType: 'ALL' | 'SINGLE';
  recipientId?: string; // clientId if SINGLE
  recipientUserId?: string; // specific userId if SINGLE
  subject: string;
  content: string;
  attachmentUrl?: string;
  attachmentName?: string;
  timestamp: Date;
  read: boolean;
  replies: MessageReply[];
}

export interface MessageReply {
  id: string;
  senderId: string;
  senderName: string;
  content: string;
  attachmentUrl?: string;
  attachmentName?: string;
  timestamp: Date;
}

export interface AppDocument {
  id: string;
  clientId: string;
  category: string; // e.g., 'regolarita-documentazione'
  type: string; // e.g., 'scia', 'camerale', etc.
  fileName: string;
  fileType: string;
  fileData?: string; // base64
  uploadDate: Date;
  expiryDate?: string; // For PEE
  userId?: string; // Specific unit/collaborator association
}

export interface ProductionIngredient {
  id: string;
  name: string;
  packingDate: string;
  expiryDate: string;
  lotto: string; // or invoice ref
  photo?: string; // base64 jpg
}

export interface ProductionRecord {
  id: string;
  recordedDate: string; // day of record (archive date)
  mainProductName: string;
  packagingDate: string;
  expiryDate: string;
  lotto: string;
  ingredients: ProductionIngredient[];
  userId: string;
  clientId: string;
}


